const body = $input.first().json.body || $input.first().json;
const remoteJid = body?.data?.key?.remoteJid || body?.data?.remoteJid || body?.remoteJid || body?.key?.remoteJid || '';
const fromMe = body?.data?.key?.fromMe === true;
const isGroup = remoteJid.includes('@g.us');
const isNewsletter = remoteJid.includes('@newsletter');
const isLid = remoteJid.includes('@lid');
const numeroLimpo = remoteJid.replace('@s.whatsapp.net','').replace('@c.us','').replace('@lid','_lid');
const msgData = body?.data?.message || {};
const messageType = body?.data?.messageType || Object.keys(msgData)[0] || '';
let mensagem = '';
let localizacao = null;
if (messageType === 'locationMessage' || msgData.locationMessage) {
  const loc = msgData.locationMessage || {};
  mensagem = '__LOCALIZACAO__';
  localizacao = { lat: loc.degreesLatitude || 0, lng: loc.degreesLongitude || 0, nome: loc.name || '' };
} else {
  mensagem = (msgData.conversation || msgData.extendedTextMessage?.text || msgData.imageMessage?.caption || msgData.documentMessage?.caption || '').trim().toLowerCase();
}
const pushName = body?.data?.pushName || body?.data?.verifiedBizName || 'Cliente';
const messageId = body?.data?.key?.id || '';
const timestamp = body?.data?.messageTimestamp || Date.now();

// === BLOQUEIO DE ATENDIMENTO HUMANO ===
const staticData = $getWorkflowStaticData('global');
if (!staticData.memoriaClientes) staticData.memoriaClientes = {};
const memoria = staticData.memoriaClientes;
const INATIVIDADE_30MIN = 30 * 60 * 1000;
const PALAVRAS_RESET_BOT = ['menu', 'bot', 'atendimento automatico', 'atendimento automático', 'opções', 'opcoes'];

if (fromMe && remoteJid) {
  if (!memoria[remoteJid]) {
    memoria[remoteJid] = { estado: 'inicio', ultima_intencao: null, etapa: 'nova_conversa', ultima_interacao: Date.now() };
  }
  memoria[remoteJid].atendimentoHumano = true;
  memoria[remoteJid].ultimaInteracaoHumana = Date.now();
}

let bloqueadoPorHumano = false;
if (!fromMe && memoria[remoteJid]?.atendimentoHumano === true) {
  const pedindoBot = PALAVRAS_RESET_BOT.includes(mensagem);
  const inativo = Date.now() - (memoria[remoteJid].ultimaInteracaoHumana || 0) > INATIVIDADE_30MIN;
  if (pedindoBot || inativo) {
    memoria[remoteJid].atendimentoHumano = false;
  } else {
    memoria[remoteJid].ultimaInteracaoHumana = Date.now();
    bloqueadoPorHumano = true;
  }
}
// === FIM BLOQUEIO ===

const podeResponder = !fromMe && !isGroup && !isNewsletter && remoteJid !== '' && !bloqueadoPorHumano;
return [{ json: { remoteJid, numeroLimpo, mensagem, mensagemOriginal: mensagem, localizacao, messageType, pushName, messageId, timestamp, fromMe, isGroup, isLid, podeResponder, bloqueadoPorHumano, _raw: body } }];

