const dados = $input.first().json;
const rawMsg = dados._raw?.data?.message || {};
const audioMsg = rawMsg.audioMessage;

if (!audioMsg) {
  return [{ json: { ...dados, audioOk: false, audioErro: 'sem_midia' } }];
}

function toBase64(obj) {
  if (!obj) return obj;
  if (typeof obj === 'object') {
    const values = Object.values(obj);
    if (values.length > 0 && typeof values[0] === 'number') {
      return Buffer.from(values).toString('base64');
    }
  }
  return obj;
}

const audioConvertido = {
  ...audioMsg,
  mediaKey: toBase64(audioMsg.mediaKey),
  fileSha256: toBase64(audioMsg.fileSha256),
  fileEncSha256: toBase64(audioMsg.fileEncSha256),
  streamingSidecar: toBase64(audioMsg.streamingSidecar)
};

return [{ json: { ...dados, audioConvertido: audioConvertido, keyAudio: dados._raw?.data?.key } }];

