const staticData = $getWorkflowStaticData('global');

if (!staticData.logsAtendimento) staticData.logsAtendimento = [];
const logs = staticData.logsAtendimento;

const numero    = dados.remoteJid || '';
const mensagem  = (dados.mensagemOriginal || dados.mensagem || '').substring(0, 200);
const resposta  = (dados.textoResposta || '').substring(0, 300);
const chamarLLM = dados.chamarLLM === true;
const mem       = (staticData.memoriaClientes || {})[numero] || {};
const estado    = mem.estado || (chamarLLM ? 'tecnico' : 'fixo');
const agora     = Date.now();

const ultimoLog = [...logs].reverse().find(l => l.numero === numero);
const deltaMs   = ultimoLog ? agora - ultimoLog.timestamp : null;

logs.push({
  numero,
  mensagemCliente: mensagem,
  respostaBot:     resposta,
  estado,
  chamarLLM,
  deltaSegundos:   deltaMs !== null ? Math.round(deltaMs / 1000) : null,
  timestamp:       agora
});

if (logs.length > 500) staticData.logsAtendimento = logs.slice(-500);

// Resumo recalculado
const all     = staticData.logsAtendimento;
const total   = all.length;
const comIA   = all.filter(l => l.chamarLLM).length;
const semIA   = total - comIA;
const deltas  = all.map(l => l.deltaSegundos).filter(d => d !== null && d < 3600);
const dMedia  = deltas.length ? Math.round(deltas.reduce((a,b)=>a+b,0)/deltas.length) : null;
const interVi = all.filter(l => l.estado === 'info').length;

staticData.resumoLogs = {
  totalInteracoes:        total,
  pctRespostasIA:         total ? +(comIA/total*100).toFixed(1) : 0,
  pctRespostasFixas:      total ? +(semIA/total*100).toFixed(1) : 0,
  pctInteresseVisita:     total ? +(interVi/total*100).toFixed(1) : 0,
  tempoMedioEntreMsg_seg: dMedia,
  atualizadoEm:           agora
};

// Pass-through: repassa dados originais para Enviar Resposta
return [{ json: dados }];
